from dataclasses import dataclass, field
from typing import List, Optional


@dataclass
class QualityMetricSnapshot:
    month: str          # ISO year-month, e.g. "2024-08"
    eval_pass_rate: float
    eval_pass_rate_prev_month: float
    user_thumbs_down_rate: float
    hallucination_rate: float
    avg_latency_p95_ms: float
    cost_per_1k_calls_usd: float

    def eval_delta(self) -> float:
        return self.eval_pass_rate - self.eval_pass_rate_prev_month

    def is_regression(self) -> bool:
        """Flag months where eval pass rate dropped by more than 2 percentage points."""
        return self.eval_delta() < -0.02

    def metrics_summary(self) -> str:
        trend = "REGRESSION" if self.is_regression() else "STABLE"
        delta_str = f"{self.eval_delta():+.1%}"
        return (
            f"[{self.month}] {trend} | "
            f"Eval: {self.eval_pass_rate:.1%} ({delta_str}) | "
            f"Thumbs-down: {self.user_thumbs_down_rate:.1%} | "
            f"Hallucination: {self.hallucination_rate:.2%}"
        )


@dataclass
class QualityRootCause:
    regression_description: str
    contributing_factors: List[str]
    root_cause: str
    evidence: str           # Concrete data that confirms this root cause
    corrective_actions: List[str]
    owner: str
    target_resolution_month: str

    def root_cause_report(self) -> str:
        factors_str = "\n  - ".join(self.contributing_factors)
        actions_str = "\n  - ".join(self.corrective_actions)
        return (
            f"Regression: {self.regression_description}\n"
            f"Root cause: {self.root_cause}\n"
            f"Evidence: {self.evidence}\n"
            f"Contributing factors:\n  - {factors_str}\n"
            f"Corrective actions:\n  - {actions_str}\n"
            f"Owner: {self.owner} | Target: {self.target_resolution_month}"
        )


@dataclass
class QualityDeepDive:
    month: str
    metrics: QualityMetricSnapshot
    regressions_reviewed: List[QualityRootCause] = field(default_factory=list)
    facilitator: str = ""
    attendees: List[str] = field(default_factory=list)

    def open_corrective_actions(self) -> List[str]:
        actions = []
        for rc in self.regressions_reviewed:
            for action in rc.corrective_actions:
                actions.append(f"[{rc.owner}] {action} (target: {rc.target_resolution_month})")
        return actions

    def deep_dive_summary(self) -> str:
        regression_flag = "REGRESSION MONTH" if self.metrics.is_regression() else "STABLE MONTH"
        return (
            f"Quality Deep Dive {self.month} [{regression_flag}]\n"
            f"{self.metrics.metrics_summary()}\n"
            f"Regressions reviewed: {len(self.regressions_reviewed)}\n"
            f"Open corrective actions: {len(self.open_corrective_actions())}"
        )

from dataclasses import dataclass, field
from enum import Enum
from typing import List, Optional
import datetime


class RetroSource(Enum):
    SPRINT_RETRO      = "sprint_retro"
    QUALITY_DEEP_DIVE = "quality_deep_dive"
    ARCHITECTURE_RETRO = "architecture_retro"
    INCIDENT_RETRO    = "incident_retro"


class ActionItemPriority(Enum):
    CRITICAL = "critical"   # Must be resolved this sprint
    HIGH     = "high"       # Should be resolved this PI
    MEDIUM   = "medium"     # Backlog; will be reviewed at next quarter retro
    LOW      = "low"        # Nice-to-have; retire if not picked up in 2 quarters


@dataclass
class ImprovementActionItem:
    item_id: str
    source: RetroSource
    source_session_id: str    # Sprint id, month, quarter, or incident id
    description: str
    owner: str
    priority: ActionItemPriority
    target_date: str          # ISO-8601
    claude_category: str      # e.g. "prompt_quality", "eval_coverage", "model_upgrade"
    status: str = "open"      # open | in_progress | done | deferred
    completed_date: Optional[str] = None
    completion_notes: str = ""

    def is_overdue(self) -> bool:
        if self.status in ("done", "deferred"):
            return False
        return datetime.date.today() > datetime.date.fromisoformat(self.target_date)

    def age_days(self) -> int:
        target = datetime.date.fromisoformat(self.target_date)
        created_approx = target  # Approximate; in practice use created_at field
        return (datetime.date.today() - created_approx).days


class ImprovementBacklog:
    def __init__(self) -> None:
        self._items: List[ImprovementActionItem] = []

    def add(self, item: ImprovementActionItem) -> None:
        self._items.append(item)

    def overdue(self) -> List[ImprovementActionItem]:
        return [i for i in self._items if i.is_overdue()]

    def by_category(self, category: str) -> List[ImprovementActionItem]:
        return [i for i in self._items if i.claude_category == category]

    def by_source(self, source: RetroSource) -> List[ImprovementActionItem]:
        return [i for i in self._items if i.source == source]

    def sprint_candidates(
        self, max_items: int = 3
    ) -> List[ImprovementActionItem]:
        """Top items to bring into a sprint; highest priority, oldest first."""
        open_items = [
            i for i in self._items if i.status in ("open", "in_progress")
        ]
        sorted_items = sorted(
            open_items,
            key=lambda i: (
                ["critical", "high", "medium", "low"].index(i.priority.value),
                i.target_date,
            )
        )
        return sorted_items[:max_items]

    def health_report(self) -> str:
        overdue = self.overdue()
        open_items = [i for i in self._items if i.status == "open"]
        return (
            f"Improvement Backlog Health\n"
            f"  Total items: {len(self._items)}\n"
            f"  Open: {len(open_items)}\n"
            f"  Overdue: {len(overdue)}\n"
            f"  By source: "
            + ", ".join(
                f"{src.value}={len(self.by_source(src))}"
                for src in RetroSource
            )
        )
